package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP09GenerarCuentaPlaywrightTest extends BaseTestPlaywright {    @Test    void generarCuentaCorrectamenteParaPedidoCompletado() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']").fill("camarero");        page.locator("input[name='password']").fill("123");        page.locator("button[type='submit']").click();        page.waitForTimeout(2000);        long cantidadPreBoletas =                page.locator("a:has-text('Pre-Boleta')")                        .count();        assertTrue(                cantidadPreBoletas > 0,                "No existe ningún pedido entregado con opción Pre-Boleta."        );        page.locator("a:has-text('Pre-Boleta')")                .first()                .click();        page.waitForTimeout(2000);        assertTrue(                page.content().contains("Detalle del Pedido"),                "No se visualiza el detalle del pedido."        );        assertTrue(                page.content().contains("Total Importe")                        && page.content().contains("IGV")                        && page.content().contains("Total"),                "No se visualizan correctamente los totales de la cuenta."        );        assertTrue(                page.locator("button:has-text('Completar Pago')")                        .count() > 0,                "No se visualiza el botón Completar Pago."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get(                                "evidencias/HP09-generar-cuenta.png"))                        .setFullPage(true)        );    }}